import heapq

def func(lists, k):
    # Create a dictionary to store the frequency of each integer
    freq_dict = {}

    # Iterate over each list and update the frequency dictionary
    for lst in lists:
        for num in lst:
            if num in freq_dict:
                freq_dict[num] += 1
            else:
                freq_dict[num] = 1

    # Use a min heap to keep track of top k elements
    min_heap = []

    # Iterate over the frequency dictionary and maintain a min heap of size k
    for num, freq in freq_dict.items():
        if len(min_heap) < k:
            heapq.heappush(min_heap, (freq, num))
        elif freq > min_heap[0][0]:
            heapq.heappop(min_heap)
            heapq.heappush(min_heap, (freq, num))

    # Extract the numbers from the heap and sort them by frequency in descending order
    top_k = [heapq.heappop(min_heap)[1] for _ in range(len(min_heap))]
    top_k.sort(key=lambda x: freq_dict[x], reverse=True)

    return top_k

