def is_majority(arr):
    n = len(arr)
    if n == 0:
        return False

    # Find the middle element
    mid_index = n // 2
    candidate = arr[mid_index]

    # Check if the candidate is a majority element
    first_occurrence = binary_search_first(arr, candidate)
    if first_occurrence == -1:
        return False

    # Check if the candidate appears more than n/2 times
    if (first_occurrence + n // 2) < n and arr[first_occurrence + n // 2] == candidate:
        return True

    return False

def binary_search_first(arr, target):
    left, right = 0, len(arr) - 1
    result = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            result = mid
            right = mid - 1
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return result
