def max_sum_increasing_subseq(arr, n, k):
    # Initialize the dp array where dp[i] will store the maximum sum of increasing subsequence till index i
    dp = [0] * n

    # Base case: The maximum sum at the first element is the element itself
    dp[0] = arr[0]

    # Fill the dp array
    for i in range(1, n):
        dp[i] = arr[i]
        for j in range(i):
            if arr[j] < arr[i]:
                dp[i] = max(dp[i], dp[j] + arr[i])

    # Include the kth element which is after i
    max_sum = 0
    for i in range(n-1):
        if arr[i] < arr[k]:
            max_sum = max(max_sum, dp[i] + arr[k])

    return max_sum

