def __init__(self, arrays):
    min_val = float('inf')
    max_val = float('-inf')
    ranges = []

    for arr in arrays:
        if not arr:
            return None  # Return None if any array is empty

        min_val = min(min_val, arr[0])
        max_val = max(max_val, arr[-1])
        ranges.append((arr[0], arr[-1]))

    smallest_range = (min_val, max_val)
    range_diff = max_val - min_val

    for start, end in ranges:
        while start < end and end - start > range_diff:
            if start == min_val:
                break
            start += 1
            if end - start < range_diff:
                smallest_range = (start, end)
                range_diff = end - start

    return smallest_range

