def newman_prime(n):
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    def newman_shanks_williams(n):
        if n == 1:
            return 2
        if n == 2:
            return 3
        a, b = 2, 3
        for _ in range(3, n + 1):
            a, b = b, (b * b - 2) % (2 * b)
        return b

    count = 0
    num = 2
    while True:
        if is_prime(newman_shanks_williams(num)):
            count += 1
            if count == n:
                return newman_shanks_williams(num)
        num += 1

